import React, { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { CreditCard, Smartphone, Building2, Lock } from 'lucide-react';
import { useCart } from '../context/CartContext';
import { toast } from 'react-toastify';
import '../assets/styles/Payment.css';

const API_BASE = 'http://localhost:5000';

const Payment = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { cartItems, cartTotal, clearCart } = useCart();
  const addressId = location.state?.addressId;

  const [paymentTab, setPaymentTab] = useState('upi');
  const [upiId, setUpiId] = useState('');
  const [cardData, setCardData] = useState({ number: '', name: '', expiry: '', cvv: '' });
  const [processing, setProcessing] = useState(false);

  const deliveryFee = cartTotal > 500 ? 0 : 49;
  const finalTotal = cartTotal + deliveryFee;

  const getAuthHeaders = () => ({
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${localStorage.getItem('token')}`
  });

  const handlePay = async () => {
    if (paymentTab === 'upi' && !upiId.includes('@')) {
      toast.error('Please enter a valid UPI ID (e.g. name@upi)');
      return;
    }
    if (paymentTab === 'card' && (!cardData.number || !cardData.name || !cardData.expiry || !cardData.cvv)) {
      toast.error('Please fill all card details.');
      return;
    }

    setProcessing(true);
    // Simulate payment processing delay
    setTimeout(async () => {
      try {
        const res = await fetch(`${API_BASE}/api/order`, {
          method: 'POST',
          headers: getAuthHeaders(),
          body: JSON.stringify({ addressId, paymentMethod: paymentTab.toUpperCase() })
        });
        const data = await res.json();
        if (data.success) {
          await clearCart();
          navigate('/order-success', { state: { order: data.order } });
        } else {
          toast.error(data.message);
          setProcessing(false);
        }
      } catch (err) {
        toast.error('Payment failed. Please try again.');
        setProcessing(false);
      }
    }, 2000);
  };

  return (
    <div className="payment-page">
      <div className="payment-container">
        <div className="payment-grid">
          {/* Left: Payment Methods */}
          <div className="payment-methods-panel">
            <div className="payment-header">
              <Lock size={16} />
              <h2>Secure Payment</h2>
            </div>

            <div className="payment-tabs">
              <button className={`pay-tab ${paymentTab === 'upi' ? 'active' : ''}`} onClick={() => setPaymentTab('upi')}>
                <Smartphone size={16} /> UPI
              </button>
              <button className={`pay-tab ${paymentTab === 'card' ? 'active' : ''}`} onClick={() => setPaymentTab('card')}>
                <CreditCard size={16} /> Card
              </button>
              <button className={`pay-tab ${paymentTab === 'netbanking' ? 'active' : ''}`} onClick={() => setPaymentTab('netbanking')}>
                <Building2 size={16} /> Net Banking
              </button>
            </div>

            {paymentTab === 'upi' && (
              <div className="pay-form">
                <h3>Pay via UPI</h3>
                <div className="upi-apps">
                  {['GPay', 'PhonePe', 'Paytm'].map(app => (
                    <button key={app} className="upi-app-btn">{app}</button>
                  ))}
                </div>
                <div className="pay-divider"><span>or enter UPI ID</span></div>
                <label>UPI ID</label>
                <input
                  type="text" placeholder="yourname@upi"
                  value={upiId} onChange={e => setUpiId(e.target.value)}
                />
              </div>
            )}

            {paymentTab === 'card' && (
              <div className="pay-form">
                <h3>Pay via Card</h3>
                <label>Card Number</label>
                <input type="text" placeholder="1234 5678 9012 3456" maxLength={19}
                  value={cardData.number} onChange={e => setCardData({...cardData, number: e.target.value})} />
                <label>Cardholder Name</label>
                <input type="text" placeholder="Name on card"
                  value={cardData.name} onChange={e => setCardData({...cardData, name: e.target.value})} />
                <div className="card-row">
                  <div>
                    <label>Expiry</label>
                    <input type="text" placeholder="MM/YY" maxLength={5}
                      value={cardData.expiry} onChange={e => setCardData({...cardData, expiry: e.target.value})} />
                  </div>
                  <div>
                    <label>CVV</label>
                    <input type="password" placeholder="•••" maxLength={3}
                      value={cardData.cvv} onChange={e => setCardData({...cardData, cvv: e.target.value})} />
                  </div>
                </div>
              </div>
            )}

            {paymentTab === 'netbanking' && (
              <div className="pay-form">
                <h3>Net Banking</h3>
                <label>Select your bank</label>
                <select>
                  <option>State Bank of India</option>
                  <option>HDFC Bank</option>
                  <option>ICICI Bank</option>
                  <option>Axis Bank</option>
                  <option>Kotak Mahindra</option>
                </select>
              </div>
            )}
          </div>

          {/* Right: Summary & Pay */}
          <div className="payment-summary-panel">
            <h3>Payment Summary</h3>
            <div className="pay-summary-items">
              {cartItems.map(item => (
                <div key={item.itemId} className="pay-summary-row">
                  <span>{item.title} × {item.quantity}</span>
                  <span>₹{(item.price * item.quantity).toFixed(2)}</span>
                </div>
              ))}
            </div>
            <div className="pay-total-rows">
              <div className="pay-total-row"><span>Subtotal</span><span>₹{cartTotal.toFixed(2)}</span></div>
              <div className="pay-total-row"><span>Delivery</span><span>{deliveryFee === 0 ? 'FREE' : `₹${deliveryFee}`}</span></div>
              <div className="pay-total-row grand"><span>Total</span><span>₹{finalTotal.toFixed(2)}</span></div>
            </div>

            <button className="pay-now-btn" onClick={handlePay} disabled={processing}>
              {processing ? (
                <span className="paying-spinner">
                  <span className="spinner-dot"></span> Processing...
                </span>
              ) : (
                `Pay ₹${finalTotal.toFixed(2)}`
              )}
            </button>
            <p className="secure-note"><Lock size={12} /> 100% Secure & Encrypted Payment</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Payment;
